let _commAudioLastUiUpdate = 0;

function setCommAudioStatus(msg) {
  if (!commAudioStatusEl) return;
  commAudioStatusEl.textContent = (msg || '').toString();
}

function _fmtTime(secs) {
  const s = Math.max(0, Number(secs) || 0);
  const m = Math.floor(s / 60);
  const r = Math.floor(s - m * 60);
  return String(m).padStart(2, '0') + ':' + String(r).padStart(2, '0');
}

function _syncCommAudioUi() {
  try {
    if (!commAudioSeekEl || !commAudioTimeEl) return;
    if (!_commAudioSeg || !_commAudio) {
      if (commAudioSeekWrapEl) commAudioSeekWrapEl.style.display = 'none';
      commAudioSeekEl.disabled = true;
      commAudioSeekEl.min = '0';
      commAudioSeekEl.max = '100';
      commAudioSeekEl.value = '0';
      commAudioTimeEl.textContent = '--:-- / --:--';
      return;
    }
    if (commAudioSeekWrapEl) commAudioSeekWrapEl.style.display = 'inline-flex';
    const startS = Number(_commAudioSeg.start_s);
    const endS = Number(_commAudioSeg.end_s);
    const t = Number(_commAudio.currentTime || 0);
    if (!Number.isFinite(startS) || !Number.isFinite(endS) || endS <= startS) return;

    commAudioSeekEl.disabled = false;
    commAudioSeekEl.min = String(startS);
    commAudioSeekEl.max = String(endS);
    if (!_commAudioUserSeeking) {
      const clamped = Math.min(Math.max(t, startS), endS);
      commAudioSeekEl.value = String(clamped);
    }
    const cur = Math.min(Math.max(t - startS, 0), Math.max(endS - startS, 0));
    const dur = Math.max(endS - startS, 0);
    commAudioTimeEl.textContent = _fmtTime(cur) + ' / ' + _fmtTime(dur);
  } catch (e) {}
}

async function loadAudioMapOnce() {
  if (_audMap) return _audMap;
  if (_audMapLoad) return _audMapLoad;
  _audMapLoad = (async () => {
    try {
      const m = await fetchJson('/aud/audio_map.json', { method: 'GET' });
      _audMap = (m && typeof m === 'object') ? m : {};
    } catch (e) {
      _audMap = {};
    }
    return _audMap;
  })();
  return _audMapLoad;
}

function _syncCommAudioButtons(state) {
  // state: 'idle' | 'playing' | 'paused'
  if (!commAudioPlayBtn || !commAudioPauseBtn || !commAudioStopBtn) return;
  if (state === 'playing') {
    commAudioPlayBtn.style.display = 'none';
    commAudioPauseBtn.style.display = '';
    commAudioStopBtn.style.display = '';
  } else if (state === 'paused') {
    commAudioPlayBtn.style.display = '';
    commAudioPauseBtn.style.display = 'none';
    commAudioStopBtn.style.display = '';
  } else {
    commAudioPlayBtn.style.display = '';
    commAudioPauseBtn.style.display = 'none';
    commAudioStopBtn.style.display = 'none';
  }
  _syncCommAudioUi();
}

function _stopCommAudioInternal({ quiet } = {}) {
  try {
    if (_commAudio) {
      _commAudio.pause();
      _commAudio.currentTime = 0;
    }
  } catch (e) {}
  _commAudioSeg = null;
  if (!quiet) setCommAudioStatus('');
  _syncCommAudioButtons('idle');
}

function _installBoundaryEnforcer() {
  if (_commAudioTick) return;
  _commAudioTick = setInterval(() => {
    try {
      if (!_commAudio || !_commAudioSeg) return;
      const now = Date.now();
      // Keep UI responsive without updating on every tick while the user is dragging the slider.
      if (now - _commAudioLastUiUpdate > 180) {
        _commAudioLastUiUpdate = now;
        _syncCommAudioUi();
      }
      const endS = Number(_commAudioSeg.end_s);
      if (!Number.isFinite(endS) || endS <= 0) return;
      const t = Number(_commAudio.currentTime || 0);
      if (t >= endS - 0.05) {
        _stopCommAudioInternal({ quiet: true });
        setCommAudioStatus('Done.');
      }
    } catch (e) {}
  }, 120);
}
